// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務室的門被推開的時候，澪以為進來的會是另一個陌生面孔。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從她被帶進這間房間到現在，已經換過兩個人了。第一個是站務主管，問她車廂編號和上車時間。第二個是一個年輕警員，把她的手機拿去拍照、記錄匿名訊息、備份對話紀錄。每一個人都很忙，每一個人都只負責自己那段流程，沒有人完整地聽她說過一次話。像一條輸送帶，每個人只接手她的一部分，沒有人看過完整的她。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門開了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見皮鞋。黑色的、舊的、鞋底磨偏了的皮鞋。然後是深色西裝褲的褲腳。然後是一隻手推開門，把門撐住，讓後面的人跟進來。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪抬頭。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯日下部。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部悟。警視廳刑警。上次見面是在警署受理台旁邊，他叫她別一個人去研究中心。再上次是在她家附近的便利商店外面，他沒收了她的手機，叫她別查了。每一次出現，他都像從牆縫裡長出來的——沒有預告，沒有解釋，只有一句命令和一個讓她不舒服的眼神。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他進來了。後面跟著那個年輕警員，手裡抱著一疊資料夾。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部沒有看她。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他先走到桌邊，翻開最上面那個資料夾。看了幾秒。然後他拿起桌上的證物袋——裝著銀色外殼的那個透明袋——把它舉到燈光下面，轉了一下，看外殼的破邊和金色接點。他看了很久。比澪預期的久。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他放下證物袋，看了一眼旁邊另一個袋子——裝著她染血外套的那個。他沒有拿起來，只是低頭看了看標籤。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他看她的手。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的雙手放在桌面上。掌心朝下。手指已經被清理過了——救護人員在月台上幫她擦過血，指甲縫裡的殘留被棉片帶走，掌心的乾涸血跡被生理食鹽水化開。但她的手看起來仍然不對。皮膚發紅，是被反覆擦拭過的那種紅。指節偏白，是握得太久又突然鬆開的那種白。手背上有一道淺淺的刮痕，她不記得是什麼時候弄的。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部看完她的手，才看她的臉。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "妳還是上車了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。沒有問號。語氣平得像在讀一個已經寫好的結論。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯你怎麼在這裡？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "朝倉澪。跟既有失蹤案有關。灣岸新交通重大傷害事件。死者遺言提到「東京」，還有疑似災害的話。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他像在念案由。一條一條，從資料夾上抬起來的。每條之間停頓半秒，像在讓她確認這些都是真的。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "同事看到妳的名字通知我。朝倉悠真的案子，我接手。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說完這段話，把資料夾合上，放在桌面上。動作不重，但合上的聲音在安靜的房間裡很清楚。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他在監視我。從一開始就在。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想說「你憑什麼」。但她知道答案。她父親的舊案、悠真的失蹤案、她出現在死亡事件的現場——任何一條都夠讓一個刑警用「相關」這個字把她圈進管轄範圍。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說話。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "我說過，有些地方不是靠近真相，是靠近危險。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "你說過很多話。沒有一句解釋過為什麼。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部沒有接。他拉開椅子坐下，把那疊資料夾往自己這邊挪了挪。年輕警員在他旁邊坐下，打開筆電，螢幕上是問話紀錄的表格。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務主管從門外探進頭來。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.StationStaff, character: "站務主管", dialogue: "中央流可以先看。車載原始檔要等車輛封存後，技術班再來抽。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說這句話的時候在看日下部，像在等指示。日下部沒有立刻回話。他翻開資料夾，看了一行字——澪看不見是哪一行——然後合上。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "那就現在封存。不要覆蓋。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Determined },
    { characterId: CharacterId.StationStaff, character: "站務主管", dialogue: "⋯⋯現在？", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "現在。事故車封存。車載資料單元不要動，等技術班抽。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站務主管看了他一眼，點了個頭，退出去。門帶上的時候，房間又安靜了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)車載原始檔。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道那是什麼。但她聽見了「不要覆蓋」這三個字。這三個字不像命令，像在保護什麼。她不知道他在保護什麼，也不知道他為什麼要保護。她只知道剛才站務主管說的「中央流」是控制中心那個版本——那個少了千田把外殼交給她的版本的畫面。如果還有另一份資料存在車上，那它可能記得中央流忘記的事。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她沒有時間想。日下部已經在看證物袋了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把裝著銀色外殼的透明袋拿起來，翻到標籤那面。黑色奇異筆的字跡。她認得那些字——她在月台上就看見了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現場暫稱：刃物狀金屬片 / 第七車 / 朝倉澪手邊發現。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "先不要寫「兇器」。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他對年輕警員說的。語氣很平，像在改一個錯字。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "正式紀錄寫「金屬外殼狀物」。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "⋯⋯金屬外殼狀物？", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "刃物狀是現場暫稱。鑑定還沒出來。在結果出來前，正式紀錄別先定性。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "年輕警員在筆電上改了幾個字。日下部把證物袋放回桌上。他沒有看澪。他在看螢幕上的列車平面圖。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他改了標籤。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從「刃物狀金屬片」改成「金屬外殼狀物」。六個字的差別。她不知道這六個字在程序上意味著什麼。但她剛才在月台上學到了一件事——標籤寫什麼，後面的人就會用什麼角度去看它。寫「刃物」，它就是刀。寫「金屬外殼」，它就還沒有被決定是什麼。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道日下部為什麼改。她甚至不確定他是在幫她，還是在幫另一個什麼她不知道的東西。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他終於轉過來看她了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "從頭說。為什麼上車。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我收到一封訊息。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說了。從匿名訊息開始——想知道朝倉悠真在哪裡，今晚二十一點十七分，灣岸新交通，新木場方向，第七車，帶上悠真留下的那件東西，不要報警。她說她去了。她說她帶了那件東西。她說她進了第七車，看見千田浩介坐在裡面。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說到「他把東西交給我」的時候，雙手不自覺地往桌面上收了一下。不是握拳，是那種想把什麼東西護住的動作——手指往掌心蜷，手臂往身體收。她的右肘碰到了斜背包的背帶。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部的視線落在她的動作上。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只一秒。他的眼睛從她的手移到她的肘，再移到斜背包的背帶，再移回她的臉。整個過程很快，快到她不確定他到底有沒有在看。但她感覺到了——那種被掃描的感覺，像他不是在看她，是在看她身上有什麼東西的位置。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有問。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他什麼都沒問。他只是把視線收回去，低頭在資料夾上寫了一行字。她看不見他寫了什麼。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他看見了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道他看見了什麼。她甚至不確定自己剛才那個動作有沒有暴露什麼。但她的手指還在往掌心蜷，背帶還被她的肘壓著。她花了兩秒才讓自己鬆開。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部翻了一頁資料。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "訊息裡說的「那件東西」是什麼？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "來了。這個問題她在月台上已經被問過一次。那個時候她猶豫了，然後程序把她帶走了——先處理外殼、血衣、手機，這個問題被擱置。現在她又被問了。同一個問題。同一個她還沒有準備好回答的問題。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯悠真留下的東西。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "什麼東西？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣沒有追逼。平的。像在填表格。但「平」本身就是壓力——它代表他不在乎她為什麼猶豫，他只要答案。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她張嘴。她差點就說了。差點就說出「鏡子」兩個字。然後她想起外殼被封袋的那一刻。它從「千田交給她的東西」變成了「刃物狀金屬片」。她想起外套被收走的那一刻。它從「急救的痕跡」變成了「血跡證據」。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她害怕小鏡子也會變成那樣。從「悠真留下的東西」變成「證物編號幾號」。從她弟弟最後的線索變成一個被裝進透明袋裡的、不再屬於她的東西。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯一件私人物。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽見自己的聲音。很穩。比她感覺到的穩。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "私人物。帶去了？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "帶去了。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "現在在哪裡？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有立刻回答。她的手指又動了一下——很輕，往背包的方向。她控制住了。但那一秒的停頓已經夠長了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部看著她。他的眼睛在燈光下很暗，像兩個沒有開燈的房間。她讀不出他在想什麼。他在等。他沒有催，也沒有放過。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯在背包裡。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說了。她不知道為什麼說了。也許是因為她知道他不會放過這個問題。也許是因為她剛才那個動作已經告訴他了。也許是因為她太累了，太累了沒辦法同時對抗系統和這個人。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部沒有叫她拿出來。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有說「讓我看看」。他沒有說「交出來」。他只是低頭在資料夾上又寫了一行字。然後他翻到下一頁。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "車上發生了什麼。從你進車廂開始。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他跳過了。他跳過了「那件東西是什麼」這個問題，直接往下走。她不知道他是放過了她，還是把這個問題存起來了——像把一顆還沒引爆的東西放進口袋裡，等以後再拿出來。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他沒有收。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道為什麼。她不知道這是程序排序——先問車內事件，私人物之後再列清單——還是別的什麼。她只知道小鏡子還在她的背包裡，還在那個小布套裡，還沒有被裝進任何袋子。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她開始說。從進車廂開始。千田坐在座位上。他看見她。他讓她把那件東西拿出來。他看了背面。他說了一些她聽不太懂的話。然後他倒下了。他把外殼塞進她手裡。她按了緊急通話鈕。她壓住他的傷口。廣播叫她放下尖銳物。她放下了。門開了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說完的時候，房間裡很安靜。年輕警員在筆電上打字，鍵盤的聲音很輕。日下部沒有在寫字。他的筆停在資料夾上方，筆尖離紙面大約一公分。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在看她。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是看她的手。不是看她的背包。是看她的臉。像在找什麼東西。像在比對什麼。她不知道他在比對什麼。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "他說了什麼。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯什麼？", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "千田。他倒下之前說了什麼。全部。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪吞了一下。她知道這個問題遲早會被問。她不知道該怎麼回答。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "他說⋯⋯「不是這裡」。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停了一下。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "「別先看畫面。血比較老實。」", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又停了一下。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "「他們會說是救援。」", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最後一句。她說出來的時候，聲音比前幾句輕。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "「不要救東京。」", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字落在房間裡。年輕警員的手停在鍵盤上。他抬頭看了一眼日下部，又低下頭繼續打字。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部的筆停了。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是放下。是停。像一條正在走的路突然斷了。他的筆尖懸在紙面上方，一公分，半秒。然後他的視線從資料夾移上來，移到澪的臉上。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看她的眼神變了。不是變軟，也不是變凶。是變深。像他聽到了一個他不預期會在這裡聽到的東西。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他把視線收回去。筆落下。繼續寫。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "⋯⋯「不要救東京」。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他重複了一遍。不是在問她。是在把這四個字寫進紀錄裡。他寫的時候，筆觸比前面重了一點。她看見「東」那一筆的墨水在紙上洇開了一點。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有追問。他沒有問「東京是什麼」。他沒有問「他為什麼這樣說」。他只是寫下來了，然後翻到下一頁。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪不知道他為什麼停了那半秒。她不知道那半秒是什麼意思。她只知道，在所有聽過這四個字的人裡面，日下部是唯一一個沒有當場追問的人。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這讓她更不安。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是因為他追問會更好。而是因為不追問代表他已經有了一個她不知道的答案。或者，他在想一個她不知道的問題。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "今天的部分到這裡。接下來正式問話。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他合上資料夾。站起來。椅子腿在地面上刮了一聲。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走到門口的時候，停了一下。沒有回頭。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "回答妳確定的事。不要替死者解釋。", background: Background.Chapter_3_Ch3_Act4_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他推開門。走廊的燈光從門縫裡切進來，把他的影子拉長了。然後他出去了。門帶上。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪坐在原處。她的手放在桌面上。掌心朝下。斜背包掛在椅背上，背帶垂在她手肘旁邊。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不知道他剛才做的那些事——改標籤、要求封存車載資料、跳過小鏡子——是在幫她，還是在佈一個她看不見的局。她不知道他停筆那半秒是因為什麼。她不知道他為什麼不追問「不要救東京」。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她只知道一件事。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了她護住背包的動作。他什麼都沒說。", background: Background.Chapter_3_Ch3_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這比他說任何話都可怕。", background: Background.Chapter_3_Ch3_Act4_S0 },
];
